@Slf4j
public class CachedArtikelService implements CachedService, ArtikelService {

    @Autowired
    private ArtikelService artikelService;

    @Autowired
    private DataSource dataSource;

    private static final ThreadLocal<CachedArtikelBuffer> BUFFER = new ThreadLocal<>();

    public CachedArtikelService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ARTIKEL);
    }

    @Override
    public Artikel getbyFamilieArtikelDelen(Admin admin, ArtikelFamilie familie, Set<ArtikelDeel> delen) {
        TimeLogContext.getInstance().startTimeLogging("CachedArtikelService.getbyFamilieArtikelDelen");
        CachedArtikelBuffer buffer = CachedArtikelService.getBuffer();
        ArtikelKey key = new ArtikelKey(familie, delen);
        Artikel result = buffer.getByKey(key);
        if (result == null) {
            result = artikelService.getbyFamilieArtikelDelen(admin, familie, delen);
            if (result == null) {
                log.warn("Artikel niet gevonden voor key : {}", key);
            } else {
                buffer.put(key, result);
            }
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    @Override
    public void clearCache() {
        CachedArtikelService.getBuffer().clear();
    }


    private static class CachedArtikelBuffer {

        private final Map<ArtikelKey, Artikel> artikelBuffer = new HashMap<>();
        private final Map<Integer, Artikel> artikelIdBuffer = new HashMap<>();

        public Artikel getByKey(ArtikelKey key) {
            return artikelBuffer.get(key);
        }

        public Artikel getById(Integer id) {
            return artikelIdBuffer.get(id);
        }

        public void put(ArtikelKey key, Artikel artikel) {
            artikelBuffer.put(key, artikel);
            artikelIdBuffer.put(artikel.getId(), artikel);
        }

        public void clear() {
            this.artikelBuffer.clear();
            this.artikelIdBuffer.clear();
        }

    }

    private static CachedArtikelBuffer getBuffer() {
        CachedArtikelBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedArtikelBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    private static class ArtikelKey {

        private Integer familieId;
        private Integer actieId;
        private Integer beleidsitemId;
        private Integer algemeneRekeningId;
        private Integer budgettaireEntiteitId;
        private Integer budgethouderId;
        private Integer investeringsenveloppeId;
        private Integer kostenplaatsId;

        public ArtikelKey() {
            // default constructor
        }

        public ArtikelKey(ArtikelFamilie familie, Set<ArtikelDeel> delen) {
            familieId = familie.getId();
            actieId = getArtikelDeelId(delen, Boekhoudingdeeltype.BBC_ACTIE);
            beleidsitemId = getArtikelDeelId(delen, Boekhoudingdeeltype.BBC_BELEIDSITEM);
            algemeneRekeningId = getArtikelDeelId(delen, Boekhoudingdeeltype.BBC_ALGEMENE_REKENING);
            budgettaireEntiteitId = getArtikelDeelId(delen, Boekhoudingdeeltype.BBC_BUDGETTAIRE_ENTITEIT);
            budgethouderId = getArtikelDeelId(delen, Boekhoudingdeeltype.BBC_BUDGETHOUDER);
            investeringsenveloppeId = getArtikelDeelId(delen, Boekhoudingdeeltype.BBC_INVESTERINGSENVELOPPE);
            kostenplaatsId = getArtikelDeelId(delen, Boekhoudingdeeltype.BBC_KOSTENPLAATS);
        }

        private Integer getArtikelDeelId(Set<ArtikelDeel> delen, Boekhoudingdeeltype type) {
            ArtikelDeel deel = delen.stream().filter(o -> o.getType().getBoekhoudingDeelType().compareTo(type.getId()) == 0).findFirst().orElse(null);
            if (deel != null) {
                return deel.getId();
            }
            log.warn("ArtikelDeel niet gevonden voor type :{}", type.getLangeTekst());
            return null;
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) {
                return true;
            }
            if (o == null || getClass() != o.getClass()) {
                return false;
            }

            ArtikelKey that = (ArtikelKey) o;

            if (!Objects.equals(familieId, that.familieId)) {
                return false;
            }
            if (!Objects.equals(actieId, that.actieId)) {
                return false;
            }
            if (!Objects.equals(beleidsitemId, that.beleidsitemId)) {
                return false;
            }
            if (!Objects.equals(algemeneRekeningId, that.algemeneRekeningId)) {
                return false;
            }
            if (!Objects.equals(budgettaireEntiteitId, that.budgettaireEntiteitId)) {
                return false;
            }
            if (!Objects.equals(budgethouderId, that.budgethouderId)) {
                return false;
            }
            if (!Objects.equals(investeringsenveloppeId, that.investeringsenveloppeId)) {
                return false;
            }
            return Objects.equals(kostenplaatsId, that.kostenplaatsId);
        }

        @Override
        public int hashCode() {
            int result = familieId != null ? familieId.hashCode() : 0;
            result = 31 * result + (actieId != null ? actieId.hashCode() : 0);
            result = 31 * result + (beleidsitemId != null ? beleidsitemId.hashCode() : 0);
            result = 31 * result + (algemeneRekeningId != null ? algemeneRekeningId.hashCode() : 0);
            result = 31 * result + (budgettaireEntiteitId != null ? budgettaireEntiteitId.hashCode() : 0);
            result = 31 * result + (budgethouderId != null ? budgethouderId.hashCode() : 0);
            result = 31 * result + (investeringsenveloppeId != null ? investeringsenveloppeId.hashCode() : 0);
            result = 31 * result + (kostenplaatsId != null ? kostenplaatsId.hashCode() : 0);
            return result;
        }

        @Override
        public String toString() {
            return "ArtikelKey{" + "familieId=" + familieId + ", actieId=" + actieId + ", beleidsitemId=" + beleidsitemId + ", algemeneRekeningId="
                    + algemeneRekeningId + ", budgettaireEntiteitId=" + budgettaireEntiteitId + ", budgethouderId=" + budgethouderId
                    + ", investeringsenveloppeId=" + investeringsenveloppeId + ", kostenplaatsId=" + kostenplaatsId + '}';
        }
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
