    @Override
    @InitializeAdmin
    public Set<Artikel> findByIds(Admin admin, Set<Integer> ids) {
        return findByIds(admin, ids, "");
    }

    @Override
    @InitializeAdmin
    public Set<Artikel> findByObjectIds(Admin admin, Set<Artikel> objects) {
        return findByObjectIds(admin, objects, "");
    }

    @Override
    @InitializeAdmin
    public Set<Artikel> findByIds(Admin admin, Set<Integer> ids, String fetchString) {
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.fetch(fetchString);
        cb.and("id", Criterium.IN(ids));
        return new HashSet<>(findByCriteria(admin, cb));
    }

    @Override
    @InitializeAdmin
    public Set<Artikel> findByObjectIds(Admin admin, Set<Artikel> objects, String fetchString) {
        Set<Integer> ids = objects.stream()
                .map(Identifiable::getId)
                .collect(Collectors.toSet());

        CriteriaBuilder cb = new CriteriaBuilder();
        cb.fetch(fetchString);
        cb.and("id", Criterium.IN(ids));
        return new HashSet<>(findByCriteria(admin, cb));
    }

    @Override
    @InitializeAdmin
    public Set<Artikel> findByIdstByRecordTimeAndActualFree(Admin admin, Set<Integer> ids, LocalDateTime tijdstip, String fetchString) {
        return TemporalUtil.getRecordTimeAndActualFree(tijdstip, () -> findByIds(admin, ids, fetchString));
    }

    @Override
    @InitializeAdmin
    public Set<Artikel> findByObjectIdsByRecordTimeAndActualFree(Admin admin, Set<Artikel> objects, LocalDateTime tijdstip, String fetchString) {
        return TemporalUtil.getRecordTimeAndActualFree(tijdstip, () -> findByObjectIds(admin, objects, fetchString));
    }

    @Override
    public List<Artikel> findByCriteria(Admin admin, CriteriaBuilder cb) {
