        return artikelService.findArtikelByIds(admin, ids);
    }

    @Override
    public Integer findMaxNumberOfHrArtikels(Cluster cluster, LocalDate actualDate) {
        String query = "select max(cmax) from (select count(arm.slice_unique_code) cmax from hr_artikel_master arm " +
                "inner join hr_artikel_slice ars on arm.id = ars.hr_artikelid\n" +
                "inner join hr_boekhouding_slice bos on arm.slice_unique_code = bos.unique_code\n" +
                "where ars.recordfrom <= current and ars.recordto > current\n" +
                "and bos.recordfrom <= current and bos.recordto > current\n" +
                "and bos.actualfrom <= (:actualDate) and bos.actualto > (:actualDate)\n" +
                "group by arm.slice_unique_code)";
        MapSqlParameterSource parameters = new MapSqlParameterSource();
        parameters.addValue("actualDate", Date.valueOf(actualDate.toString()));
        NamedParameterJdbcTemplate jdbcTemplate = new NamedParameterJdbcTemplate(dataSource);
        return Optional.ofNullable(jdbcTemplate.queryForObject(query, parameters, Integer.class)).orElse(0);
    }

}
